var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"CSE Lv. 5","JPN":"CSE Lv.5","ENG":"CSE Lv. 5","TWN":"CSE Lv.5"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>관리국에서 알립니다.</color>","JPN":"<color=#ffd34c>管理局からお知らせします。</color>","ENG":"<color=#ffd34c>This is the Administration.</color>","TWN":"<color=#ffd34c>管理局通知。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이것은 실제 상황입니다.</color>","JPN":"<color=#ffd34c>これは訓練ではありません。</color>","ENG":"<color=#ffd34c>This is not a drill.</color>","TWN":"<color=#ffd34c>這是實際情況。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>아직 대피하지 못한 시민분들께서는 최대한 방위선 쪽으로 이동하시기 바랍니다.</color>","JPN":"<color=#ffd34c>まだ避難していない市民の皆様は速やかに防衛線の方へ移動してください。</color>","ENG":"<color=#ffd34c>If you have not yet evacuated, proceed toward the defense line.</color>","TWN":"<color=#ffd34c>尚未撤離的市民請盡量向防線方向移動。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>대균열 확산의 여파로 도시 내부에 숨는 것은 추천해 드리지 않습니다.</color>","JPN":"<color=#ffd34c>大亀裂拡散の影響により、都市内部に隠れ留まることは推奨しません。</color>","ENG":"<color=#ffd34c>Due to the spread of the Grand Dimension Crevice, sheltering within the city is not recommended.</color>","TWN":"<color=#ffd34c>由於大峽谷的擴散的餘波，建議不要躲在城市內。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>방위선에서 멀리 떨어진 도심지에 계신 분들은 급성 침식 증후군을 조심하시길 바라며.</color>","JPN":"<color=#ffd34c>防衛線から離れた都市中心部にいる方々は、急性侵食症候群にお気をつけください。</color>","ENG":"<color=#ffd34c>Those far from the defense line, beware of acute Corruption Syndrome.</color>","TWN":"<color=#ffd34c>若身處距離防線較遠市區的市民，請注意急性侵蝕症候群。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>이미 가망이 없다는 판단이 든 분들은 신속하고 편안한 죽음을 선택하시길 바랍니다.</color>","JPN":"<color=#ff3636>すでに手遅れと判断された方は、迅速かつ安楽な死をお選びください。</color>","ENG":"<color=#ff3636>If you judge survival to be impossible, choose a swift and painless death.</color>","TWN":"<color=#ff3636>若已判斷無救治可能，請迅速選擇安樂死亡。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이상, 안내된 지침은 재난경보 해제까지 유효합니다.</color>","JPN":"<color=#ffd34c>以上、ご案内している行動指針は災難警報が解除されるまで有効です。</color>","ENG":"<color=#ffd34c>The broadcast guidelines will remain in effect until the disaster alert is lifted.</color>","TWN":"<color=#ffd34c>上述內容將維持到災難警報解除為止。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"관측 보고드립니다!","JPN":"観測報告します！","ENG":"Observation report!","TWN":"報告觀測結果！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L16_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"현재 뿌리가 뻗는 구역의 CSE 레벨이 급격하게 상승하고 있습니다!","JPN":"現在、根が張っている区域のCSEレベルが急激に上昇中！","ENG":"CSE levels are rapidly rising in the areas the roots are spreading into!","TWN":"目前根部擴散區域的CSE等級急速上升！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"나무뿌리가 계속 도시를 잠식하면……!","JPN":"このまま都市が木の根に覆われてしまったら……！","ENG":"If those roots keep engulfing the city...!","TWN":"如果樹根持續吞噬城市……！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"여기는 로터스 ARC-EA2 구역!","JPN":"こちら、ロータスARC-EA2！","ENG":"This is Lotus ARC-EA2!","TWN":"這裡是洛德斯ARC-EA2區！"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L21_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"급성 침식 재난 발생 중!","JPN":"急性侵食災害が発生中！","ENG":"Acute Corruption Disaster in progress!","TWN":"急性侵蝕災難發生中！"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"순식간에 많은 사람들이 침식체로 변했다!","JPN":"大勢の人が、なす術もなく侵食体に変化してしまった！","ENG":"People are turning into C.O.s in an instant!","TWN":"大量人員瞬間變成侵蝕體！"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"지원을 요청한다!","JPN":"支援を要請する！","ENG":"Requesting support!","TWN":"請求支援！"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"지원을……!","JPN":"支援を……！","ENG":"Reques–!","TWN":"支援……！"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"토, 통신이?","JPN":"つ、通信が？","ENG":"Th-the comms?!","TWN":"訊、訊號？"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이봐! 들려?! 대답해!","JPN":"ちょっと！　聞こえてる！？　返事して！","ENG":"Hey! Can you hear me?! Answer me!","TWN":"喂！聽得到嗎？回答我！"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"침식파 때문에 전파가 교란되고 있는 모양입니다.","JPN":"侵食波のせいでジャミングが起こっているようです。","ENG":"The signal's being scrambled by the Corruption rays.","TWN":"電波因為侵蝕波受到干擾。"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"우선 여기서 할 수 있는 것들을 하는 것이 우선입니다, 시니어님.","JPN":"今はまず、ここでできることをしましょう、シニア様。","ENG":"For now, we must focus on what we can do here, Senior.","TWN":"目前最重要的是做好能在這裡做的事，Senior。"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"나도 알아! 하지만 지금 CSE 레벨이 5까지 치솟았잖아!","JPN":"分かってる！　でも、もうCSEレベルが5まで上がってるんだよ！","ENG":"I know! But the CSE Level has hit 5!","TWN":"我知道！但CSE 等級已經飆升到5了！"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이, 이러다가 정말 CSE 레벨 6에 도달하면 어쩌지?","JPN":"こ、このままCSEレベルが6に達したらどうしよう？","ENG":"I-if it reaches Level 6, what do we do?","TWN":"再、再這樣下去，真的會達到CSE等級6嗎？"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 되면 정말 6종 침식체란 녀석이 강림할지도 모른다고!","JPN":"そうなったら、本当に第6種侵食体が降臨するかもしれない！","ENG":"If that happens, a Category 6 C.O. might really descend!","TWN":"那樣的話，說不定6級侵蝕體會降臨！"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"사도가 미온적으로 행동한 이유가 이것 때문이었나…….","JPN":"使徒が積極的に動かなかった理由はこれだったか……","ENG":"So that's why the Apostle acted lukewarm...","TWN":"這就是使徒行事不積極的原因嗎……"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"마치 뿌리가 영양분을 빨아들이는 것처럼 황폐해지는 것 같군.","JPN":"まるで根に養分を吸われているかのように、荒廃していく。","ENG":"It's draining us like roots siphoning nutrients, leaving desolation.","TWN":"就像根系吸取養分，整個地方陷入荒蕪中。"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"이건 도대체…….","JPN":"これはいったい……","ENG":"Just what is this...","TWN":"這到底……"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"으… 이, 이럴 땐 어떻게 해야…….","JPN":"う……こ、こんな時はどうすれば……","ENG":"Ooh... W-what do we even do...?","TWN":" 呃……這、這種情況該怎麼辦……"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"고뇌에 찬 얼굴이군.","JPN":"困り果てているといった顔だな。","ENG":"That's a face steeped in anguish.","TWN":"妳還真是滿臉煩惱呢。"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L45_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"최, 최고 관리자? 급한 일은 다 끝난 거야?","JPN":"さ、最高管理者？　急用は全部片付いたの？","ENG":"S-Supreme Administrator? Are your urgent matters over?","TWN":"最、最高管理者？緊急的事都結束了嗎？"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 르네 양이 무사히 도착해서 그쪽 사정을 말해줬거든.","JPN":"ああ。ルネ君が無事こちらに到着して、事情を説明してくれた。","ENG":"Yes. Renée arrived safely and briefed me.","TWN":"對。芮妮小姐已經平安抵達，告訴我那邊的情況了。"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"비록 권한은 동결되었지만, 자네의 상사로서 몇 마디 덕담 정도는 해줘야 하지 않겠나?","JPN":"権限が凍結されている身ではあるが、君の上司として労いの言葉はかけてやらねばと思ってね。","ENG":"My authority may be frozen, but as your superior I can still offer a few words.","TWN":"雖然權限被凍結，但身為妳的上司，還是該說幾句安慰的話吧？"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"흥, 이제 와서 그런 말 해봤자 하나도 도움 안 된다고.","JPN":"ふん、今更そんなこと言っても何の役にも立たないって。","ENG":"Hmph, saying that now doesn't help at all.","TWN":"哼，現在說這種話根本沒用。"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이졸데 양은 호기심이 왕성한 만큼 인정 욕구가 강해 시니어 자리를 거절할 수 없을 거란 걸 알고 있었네.","JPN":"イゾルデ君は好奇心が旺盛な分、承認欲求も強く、シニアの座を断れないだろうという確信があった。","ENG":"Your curiosity is strong, and so is your need for recognition. I knew you wouldn't refuse the Senior's seat.","TWN":"伊索德小姐好奇心旺盛，也很渴望被認可。所以我早就知道妳不可能拒絕Senior的職位。"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 호기심이 왕성하다는 건 이 세상을 발전시킬 가능성이 높다는 것이고,","JPN":"裏を返せば、溢れる好奇心とはすなわち、世界を発展させる可能性の生みの親でもあり、","ENG":"But strong curiosity means a high chance to advance this world,","TWN":"但好奇心旺盛也意味著妳有很大的潛力推動這個世界的發展，"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"인정 욕구가 강하다는 것은 책임감과 그에 받쳐주는 리더쉽이 뛰어나다는 걸세.","JPN":"強い承認欲求は、責任感と優れたリーダーシップに繋がるとも捉えられる。","ENG":"and a need for recognition often pairs with responsibility and leadership.","TWN":"而渴望被認同則代表妳有責任感及相應的領導能力。"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"역시 자네를 시니어 자리에 앉힌 건 잘한 선택이었어.","JPN":"やはり、君をシニアの座に就かせて正解だった。","ENG":"Appointing you Senior was the right choice.","TWN":"果然把妳安排到Senior的位置是正確的選擇。"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그, 그런 말 지금 해봤자…….","JPN":"い、今そういうの言われたら……","ENG":"S-saying that now is–","TWN":"現、現在說那種話也……"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"반칙… 이라고…….","JPN":"反則……だよ……","ENG":"Is... cheating...","TWN":"不公平……吧……"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시, 시니어님! 긴급 단파 연락입니다!","JPN":"シ、シニア！　緊急短波連絡です！","ENG":"S-Senior! Emergency shortwave!","TWN":"Senior！是緊急短波聯絡！"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"대균열 너머에 차원 도약 신호가 잡히고 있습니다!","JPN":"大亀裂の向こうから、次元跳躍の信号が捕捉されました！","ENG":"We've detected dimension jump signals beyond the Grand Dimension Crevice!","TWN":"在大峽谷另一端捕捉到次元躍遷信號！"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"기, 긴급 차원 도약이라고?!","JPN":"き、緊急次元跳躍！？","ENG":"A-an emergency dimension jump?!","TWN":"緊、緊急次元躍遷？！"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"우리를 지원하러 온 함선일 가능성은?","JPN":"こちらを支援するために来る艦船の可能性は？","ENG":"Could it be ships coming to aid us?","TWN":"有可能是來支援我們的艦艇嗎？"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"차원 도약 신호의 크기는 소형급.","JPN":"次元跳躍信号の規模は小型級。","ENG":"Jump signatures are small-class.","TWN":"次元躍遷信號的規模是小型等級。"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그것도 수십…… 수백…… 점점 늘어나고 있습니다.","JPN":"数は数十……数百……どんどん増えています。","ENG":"Dozens... hundreds... increasing by the moment.","TWN":"而且數量是數十……數百……不斷增加中。"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"관리국의 통신 요청에도 응답하지 않습니다!","JPN":"管理局の通信要請にも応答しません！","ENG":"They are not responding to the Administration hails!","TWN":"即使發出管理局通訊請求，也沒有回應！"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"응답이 없는 미확인 도약체들은 전부 적이라고 생각하십시오.","JPN":"応答しない未確認跳躍体はすべて敵だと思ってください。","ENG":"Treat all unresponsive U.J.Os as hostiles.","TWN":"對於沒有回應的未確認躍遷體，一律視為敵方。"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시니어님. 선로전환기의 시스템 구축은 완성된 겁니까?","JPN":"シニア様、線路転換器のシステム構築は完成できたのでしょうか？","ENG":"Senior, is the Track Switcher system complete?","TWN":"Senior，完成線路轉換器的系統構建了嗎？"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"응. 남은 건 적당한 타이밍뿐.","JPN":"うん。あとはタイミングを決めるだけ。","ENG":"Yes. All that's left is the right timing.","TWN":"完成了，只剩下選擇適當的時機。"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"실전 배치는 처음이라 우리 의도대로 작동할지는 솔직히 나도 확신이 잘 안 서.","JPN":"実戦で使うのは初めてだから、思った通りに動いてくれるかは正直私にも分からない。","ENG":"It's our first live deployment, so I can't be sure it'll work as intended.","TWN":"這是第一次實戰部署，說實話我也不太確定能否按照我們的期望運作。"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"하지만… 시도는 해 봐야지.","JPN":"でも……やってみないと。","ENG":"But... we have to try.","TWN":"但……必須要試試看。"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그게 내가 이 자리에 있는 이유니까.","JPN":"それが、私がここにいる理由だから。","ENG":"That's why I'm here.","TWN":"這就是我坐在這個位置的理由。"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"파티마. 단방향 발신은 아직 유효하지?","JPN":"ファティマ、単方向発信はまだ使えるよね？","ENG":"Fatima. Is the one-way broadcast still good?","TWN":"法蒂瑪，單向發送仍然有效嗎？"},"stage":{"bg":"CAMP_01","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕의 명령을 따를 시간이 되었으니 모두 저항을 멈추고 운명을 받아들여라.","JPN":"今こそ王のご命令を果たす時。皆抵抗を止め運命を受け入れるがよい。","ENG":"The time has come to obey the queen. Cease resistance and accept your fate.","TWN":"該是遵從王命的時候了，所有人停止抵抗，接受命運吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_ENERGY_ATTACK_SMALL_05"},{"id":"L38_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"마왕 타기리온의 첫 번째 사도, 솔리키타티오가 직접 나서 왕이 걸음 하실 길을 닦아낼 테니.","JPN":"魔王タギリオンの第一使徒、このソリキタティオが王の進まれる道を整えよう。","ENG":"I, Sollicitatio, first Apostle of Demon Lord Thagirion, shall personally clear the queen's path.","TWN":"魔王塔基里翁的第一使徒索爾奇塔提奧將親自登場，為王鋪路。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕의 병사들아. 더욱 거세게 몰아붙여라.","JPN":"王の兵士たちよ、敵をより強く追い込め。","ENG":"Soldiers of the queen, press them harder.","TWN":"王的士兵們，更猛烈地進攻吧。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"저항하는 이들에겐 극한의 고통을.","JPN":"抵抗する者には極限の苦痛を。","ENG":"To those who resist, grant utmost pain.","TWN":"反抗者承受極致的痛苦，"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"굴종하는 자에겐 자비로운 죽음을.","JPN":"屈従する者には慈悲深き死を。","ENG":"To those who submit, a merciful death.","TWN":"屈服者獲得仁慈的死亡。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕의 의지는 언제나 너희와 함께 적을 물리치리라.","JPN":"彼らには諦観してもらえねばならん。すべては、王の御心のままに。","ENG":"The queen's will shall ever be with you as you smite the foe.","TWN":"王的意志將永遠與你們同在，擊敗敵人。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"사도가 움직이기 시작했다!","JPN":"使徒が動き始めた！","ENG":"The Apostle is moving!","TWN":"使徒開始行動了！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"내, 내 몸이 멋대로……!","JPN":"か、体が勝手に……！","ENG":"M-my body is moving on its own...!","TWN":"我、我的身體不聽使喚……！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"흐아아아아! 내 팔! 내 팔이 반대로……!","JPN":"うわああああ！　俺の腕！　俺の腕が反対側に……！","ENG":"AAAAAGH! My arm! It's bending backwards–!","TWN":" 啊啊啊啊！我的手！我的手反過來了……！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_02"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"지원 요청! 지원 요청 바란다!","JPN":"支援要請！　支援要請を求む！","ENG":"Requesting support! I repeat, requesting support!","TWN":"請求支援！請求支援！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이렇게 죽고 싶지 않아! 죽고 싶지 않아! 아무나 좀 구해달라고!","JPN":"こんな死に方は嫌だ！　死にたくない！　誰でもいい、助けてくれ！","ENG":"I don't want to die! Somebody help me!","TWN":"我不想就這樣死掉！我不想死！快來人救救我！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_03"},{"id":"L8_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"아, 아. 여기는 HQ. 로터스 관리국이야. 잘 들리지?","JPN":"あ、あ、こちらHQ。ロータス管理局だけど、聞こえてる？","ENG":"Ah, ah. This is HQ, Lotus Administration. Can you hear me?","TWN":"啊、啊……這裡是HQ，洛德斯管理局。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이건 단방향 발신이야. 여기에 대고 대답해도 소용없으니까 미리 알아둬.","JPN":"この通信は単方向だから、返事してもこっちには届かないってこと、予め伝えておくね。","ENG":"This is a one-way broadcast. Replying is useless, so keep that in mind.","TWN":"聽得清楚嗎？這是單向發送，請了解對這裡回應沒有用。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"다들 상황은 잘 알고들 있으리라 믿어.","JPN":"皆状況は知っていると思う。","ENG":"I trust you all know the situation.","TWN":"我相信大家都明白情況。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"대균열은 확장하고, 이젠 정체를 알 수 없는 뿌리까지 튀어나와서 도시를 쑥대밭으로 만들고 있다는 걸 말이야.","JPN":"大亀裂は拡張し、今は得体の知れない木の根まで出てきて都市をめちゃくちゃにしてる。","ENG":"The Grand Dimension Crevice is expanding, and now unknown roots are tearing the city apart.","TWN":"大峽谷正在擴張，甚至冒出無法辨識的樹根，把城市變成廢墟。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L14_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"직할 도시뿐만 아니야.","JPN":"直轄都市だけじゃない。","ENG":"It's not just the Direct Control Cities.","TWN":"不只直轄城市，"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"여러 재건 도시가 침식체에게 침공당하고 파괴되고 있어.","JPN":"幾つもの再建都市が侵食体に襲われ、破壊されている。","ENG":"Multiple reconstruction cities are being invaded and destroyed.","TWN":"侵蝕體也正入侵並被破壞其他重建城市。"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"모두가 최선을 다해서 막고 있지만, 겨우 전선만 유지하는 정도지.","JPN":"みんなが全力で止めてくれているけど、前線を維持するだけで精一杯。","ENG":"We're doing our utmost, but barely holding the line.","TWN":"大家都盡力阻止，但僅只能守住前線而已。"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L21_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그리고 그 거대한 대균열 너머에는 마왕의 군세가 침공을 기다리고 있다고 해.","JPN":"そしてあの巨大な大亀裂の向こうには、魔王の軍勢が侵攻体制に入っているらしいの。","ENG":"And beyond that vast Grand Dimension Crevice, the Demon Lord's hosts await the invasion.","TWN":"而魔王的軍力正在那巨大的大峽谷彼端等待入侵。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"이런 젠장! 관리국 형씨! 이제 퇴각해도 되는 거 아냐?!","JPN":"こんちくしょう！　管理局さんよ！　そろそろ撤退してもいいんじゃないか！？","ENG":"Damn it! Administration! Isn't it time to fall back?!","TWN":" 該死！管理局的夥伴！現在可以撤退了吧？！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"이러다가 우리도 다 침식체들 밥이 되게 생겼다고!","JPN":"このままだと仲良く侵食体の餌になっちまう！","ENG":"At this rate we'll all end up as feed for the C.O.s!","TWN":"再這樣下去，我們也要成為侵蝕體的食物了！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"우리가 계속해서 물러난다면.","JPN":"私たちがずるずると引き下がってしまえば……","ENG":"If we keep retreating,","TWN":"如果我們不斷退後，"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"다음에 내줘야 하는 건 방위선이 아닐 겁니다.","JPN":"次に奪われるのは防衛線ではありません。","ENG":"the next thing we yield won't be the line.","TWN":"下一個要交出來的將不再只是防線。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L31_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"누군가의 자식, 누군가의 부모, 누군가의 연인이 될 테죠.","JPN":"誰かの子ども、誰かの親、誰かの恋人になるでしょう。","ENG":"It will be someone's child, parent, or lover.","TWN":"那將會是某人的孩子、某人的父母、某人的戀人。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"당신도 소중한 사람이, 지켜야 할 무언가가 있지 않습니까?","JPN":"あなたにも大切な人が、守るべき何かがあるのではありませんか？","ENG":"You have someone precious, something to protect, don't you?","TWN":"你也有重要的人、要守護的東西，不是嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"그러니까 우리는…….","JPN":"だから私たちは……","ENG":"Which is why we...","TWN":"所以我們……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"……포기해서는 안 돼.","JPN":"……諦めちゃダメ。","ENG":"...We must not give up.","TWN":"……不能放棄。"},"stage":{"bg":"OMEN_LOTUS_03","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L37_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"너, 너무 기운 빠지는 소리만 했나?","JPN":"お、落ち込んじゃう話ばっかりだった？","ENG":"W-was that too demoralizing?","TWN":"你、你也說得太令人泄氣了吧？"},"stage":{"bg":"OMEN_LOTUS_03","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"하지만 있는 그대로의 현실을 자각하는 것이 발전의 시작이라고!","JPN":"でも、ありのままの現実を自覚しないと発展できないし！","ENG":"But recognizing harsh reality is the start of progress!","TWN":"但正視現實，才是進步的開始！"},"stage":{"bg":"OMEN_LOTUS_03","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이대로 천천히 죽을까 봐 걱정할 필요는 없단 말씀.","JPN":"このままゆっくり死んでいく、なんて心配はしなくていいよ。","ENG":"And you don't need to worry about a slow death.","TWN":"我的意思是不必擔心就這樣慢慢死去。"},"stage":{"bg":"OMEN_LOTUS_03","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"로터스의 시니어이자 시대의 천재 이졸데 님이 저 녀석들을 막을 방법을 고안해냈으니까.","JPN":"ロータスのシニアであり稀代の天才、イゾルデ様がやつらを止める方法を考案したから。","ENG":"I, Isolde, Senior of Lotus and a genius of our time, have devised a way to stop them.","TWN":"洛德斯的Senior、時代天才伊索德，已經想出阻止那些傢伙的方法。"},"stage":{"bg":"OMEN_LOTUS_03","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그 방법을 실행할 수 있다면 놈들이 대균열을 통해 넘어오는 것을 막을 수 있어.","JPN":"その方法を実行さえできれば、やつらが大亀裂を通って渡って来るのを止められる。","ENG":"If we can execute it, we can block their passage through the Grand Dimension Crevice.","TWN":"只要能實行那個方法，就能阻止他們越過大峽谷中。"},"stage":{"bg":"OMEN_LOTUS_03","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그러니까…… 조금 무리라고 생각할 수 있고, 조금 억지라고 생각하더라도 내 말을 들어줘.","JPN":"だから……無茶だとか、無理だとか思うかもしれないけど……話を聞いてほしい。","ENG":"So... even if it sounds reckless or forced, listen to me.","TWN":"所以……即便你覺得有點勉強、有點牽強，也請聽我說。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L45_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"곧 선로전환기를 가동할 수 있을 거야.","JPN":"もう少しで線路転換器を稼働させられるの。","ENG":"We'll be able to activate the Track Switcher soon.","TWN":"很快就能啟動線路轉換器。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그때까지만…… 힘들더라도 조금만 더 방위선을 사수해 줘.","JPN":"それまで……大変でも、あと少しだけ防衛線を守ってほしい。","ENG":"Until then... even if it's hard, hold the line a little longer.","TWN":"到那時為止……即使辛苦，也請再多守住防線一下。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"나, 나도 이렇게 남의 희생을 강요하고 싶지는 않아!","JPN":"わ、私だって、こんな風に犠牲を強要したくないよ！","ENG":"I-I don't want to force sacrifice on anyone!","TWN":"我、我也不想強迫別人犧牲！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L1_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"나도 지금 모든 걸 걸고 전장에 나서고 있다고!","JPN":"でも私も今、すべてをかけて戦場に出てる！","ENG":"I'm staking everything and stepping onto the battlefield too!","TWN":"我現在也是賭上一切才站上戰場！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그, 그러니까 조금만…….","JPN":"だ、だからもう少しだけ……","ENG":"S-so please...","TWN":"所以請再……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"조금만 더 의지를 가지고 포기하지 말아 줘.","JPN":"もう少しだけ頑張って、諦めないで。","ENG":"Just a little more willpower. Don't give up.","TWN":"再堅持一下，不要放棄。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"높으신 양반이 저렇게 부탁하니까…….","JPN":"偉い人にあそこまで頼まれるとな……","ENG":"When the bigwig asks that like that...","TWN":"既然上位者都這麼請求了……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"조금이라도 더 힘을 내야겠군.","JPN":"もうちょっと頑張ってみるか。","ENG":"Guess we'd better push a little harder.","TWN":"那就再加油吧。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L19_1","type":"dialog","speaker":"RIFLE_SL_NULL_NULL","text":{"KOREA":"젠장! 총알이……!","JPN":"くそっ！　弾が……！","ENG":"Damn! I'm out of ammo...!","TWN":"該死！子彈……！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_SL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L20_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"어이, 내 총알을 써. 나는 아직 여유가 있으니까.","JPN":"おい、俺のを使え。俺はまだ余裕がある。","ENG":"Here, use mine. I've got some to spare.","TWN":"喂，用我的子彈吧。我還撐得住。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_SL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"한 명이라도 더 살아서 발버둥 쳐 봐야지.","JPN":"一人でも多く生き延びて、足掻いてみないとな。","ENG":"We've gotta struggle to keep even one more person alive.","TWN":"只要能讓多一個人活下來，就要堅持看看。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"굉장히 나서기 싫어하는 사람인데, 저질러 버렸네요. 이졸데 씨.","JPN":"人前に出るのがすごく苦手な人なのに、やりましたね。イゾルデさん。","ENG":"She hates the spotlight, but Isolde did it.","TWN":"最不想出頭的人結果還是出手了啊，伊索德。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"겁쟁이에 신경질적이고 조금 오만하기도 하지만, 확실히 자기가 시니어라는 자각은 있는 사람이야.","JPN":"臆病で神経質で少し傲慢なところもあるけど、自分がシニアだという自覚ははっきりしている人よ。","ENG":"Cowardly, high-strung, and a bit arrogant. But she knows she's the Senior.","TWN":"雖然有點膽小、神經質又有點傲慢，但確實很清楚知道自己是Senior。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"그이가 눈여겨 본 이유가 있었던 거지.","JPN":"彼が注目したのも分かるわ。","ENG":"There's a reason he took note of her.","TWN":"她會被注意到一定有原因。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하하, 분명 이졸데 씨가 들으면 기뻐하겠어요.","JPN":"はは、イゾルデさんが聞いたら喜びますよ。","ENG":"Haha, she'll be happy to hear that.","TWN":"哈哈，如果伊索德小姐聽到，一定會很開心。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그나저나, 큰일이네요. 닿는 모든 걸 침식시키는 나무뿌리라니…….","JPN":"それにしても大変ですね。触れたものすべてを侵食させる木の根だなんて……","ENG":"Anyway, this is bad. Roots that corrode anything they touch...","TWN":"話說回來真糟糕，竟然是會侵蝕一切的樹根……"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"사도가 버젓이 현실에 강림해서 활동하는 것도 좀 이상해.","JPN":"使徒が現実に降臨して普通に活動できるのもおかしいわ。","ENG":"And an Apostle brazenly manifesting into the Normalside is odd.","TWN":"使徒光明正大降臨現實，也有些奇怪。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"분명 현실에서 힘을 행사하면 제약이 걸려야 할 텐데.","JPN":"現実で力を使うと制限がかかるはずだけど。","ENG":"Exercising power here should come with restraints.","TWN":"明明在現實行使力量應該會受限啊？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"나무뿌리 같은 게 그런 조건을 무시하게 해주는 건 아닐까요?","JPN":"木の根がそういう条件を打ち消してくれてるんじゃないでしょうか？","ENG":"Maybe those roots negate such conditions?","TWN":"會不會是樹根讓這種條件失效了呢？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저 사도, 실제로 나무뿌리가 나타나고 나서야 움직이기 시작했잖아요.","JPN":"実際、あの使徒は木の根が現れてから動き始めましたし。","ENG":"That Apostle only started moving after the roots appeared.","TWN":"那個使徒也是在樹根出現後才開始行動的。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"그럴지도 모르겠네.","JPN":"そうかもしれないわね。","ENG":"Could be.","TWN":"有這個可能性。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"아무래도 눈으로 직접 확인해 봐야 알지 않으려나?","JPN":"やっぱり、自分の目で確かめたほうがいいんじゃないかしら。","ENG":"We'll have to see it up close.","TWN":"不管怎麼說，還是得親眼確認才知道吧？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"웃차. 그럼, 저도 슬슬 움직여야겠어요.","JPN":"よいっしょ。じゃあ、私もそろそろ動かないとですね。","ENG":"All right then. Time for me to move too.","TWN":"好，那我也該動身了。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"정비는 다 마쳤어, 중사님?","JPN":"整備は終わったの、軍曹？","ENG":"All set, Sergeant?","TWN":"中士，整備完成了嗎？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"다들 저렇게 열심히 싸우는데 제가 놀고 있을 수는 없죠.","JPN":"皆さんがあんなに頑張って戦っているのに、何もしないわけにはいきませんよ。","ENG":"Can't sit around while everyone's fighting.","TWN":"大家都這麼拼命，我可不能在旁邊閒著。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"여기서 더 놀고 있어봤자 늦게 죽기밖에 더 하겠어요?","JPN":"ここでじっとしていても、寿命が少し延びるくらいの差しかありませんし。","ENG":"Linger here and we'll only die later.","TWN":"再在這裡拖下去，也只是慢一點死而已吧？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"후훗, 중사님의 이런 점이 마음에 든다니까.","JPN":"ふふっ。軍曹のそういうところ、好きよ。","ENG":"Heh. That's what I like about you.","TWN":"呵呵，我很滿意中士這點。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"그럼, 출발해 볼까?","JPN":"じゃあ、行きましょうか。","ENG":"Let's roll.","TWN":"那麼出發吧？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"좋아, 정비 끝.","JPN":"よし、整備完了。","ENG":"Okay, checks complete.","TWN":"好，整備完成。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L6_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"그럼 우리도 출발하자.","JPN":"では、私たちも出発しましょう。","ENG":"Then we move out too.","TWN":"那我們也出發吧。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"오오! 드디어 파사의 심판을 위해 우리가 다시 나설 시간이 온 건가?!","JPN":"おお！　ついに破邪の審判に向けて、再び私たちの出番がやってきたのか！？","ENG":"O-oh! At last it's time for us to step forth for the judge of the Evil Eradication!","TWN":"哦哦！終於到了我們為破邪審判而再度上陣的時刻了嗎？！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"이번에야말로 사람들에게 우리의 멋있고 정의로운 모습을 각인시켜 주고 말겠어!","JPN":"今度こそ、私たちの格好よくて正義感溢れる姿を人々の目に焼き付けてあげる！","ENG":"This time, we'll etch our cool, righteous selves into everyone's minds!","TWN":"這一次，要把我們帥氣又正義的一面刻印在人們心中！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"다들 나대다가 다치지나 마.","JPN":"皆、でしゃばりすぎて怪我しないでくださいね。","ENG":"Just don't show off and get hurt.","TWN":"大家不要因為太興奮受傷啊。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"후훗, 조금 거친 표현이지만, 초원 씨 말이 맞아요.","JPN":"ふふっ。少し荒っぽい表現ですが、ナオさんの言う通りです。","ENG":"Haha, rough as it is, she's right.","TWN":" 呵呵，雖然太直白，但初源說得沒錯。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"리더? 일은 무사히 끝마치신 건가요?","JPN":"リーダー？　仕事は無事終わったのですか？","ENG":"Leader? You wrapped things up safely?","TWN":"老大？任務已經順利完成了嗎？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 여러분들이 힘내 주신 덕분이에요.","JPN":"はい。皆さんが頑張ってくれたおかげです。","ENG":"Yes. Thanks to your efforts.","TWN":" 嗯。多虧大家努力，我們才能到這裡。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"다들 준비는 잘하고 계신가요?","JPN":"準備は順調ですか？","ENG":"Are you all set?","TWN":"大家準備好了嗎？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"물론이지! 리더가 준 리액터 덕분에 다치지 않고 무사히 여기까지 올 수 있었어!","JPN":"もちろん！　リーダーがくれたリアクターのおかげで怪我もなくここまで来れたよ！","ENG":"Of course! The reactor you gave us kept us safe and got us here!","TWN":"當然囉！多虧老大提供的電抗器，我們才能毫髮無傷到這裡！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"다행이네요.","JPN":"それはよかったです。","ENG":"I'm glad.","TWN":"真是太好了。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저는 그라운드 원에서 여러분들을 기다리고 있을게요.","JPN":"私はグラウンド・ワンで皆さんを待つことにします。","ENG":"I'll be waiting at Ground One.","TWN":"我會在Ground 1等你們。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"여러분들을 믿고 있으니까요.","JPN":"皆さんを信じてますから。","ENG":"I believe in you.","TWN":"因為我相信你們。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"음! 걱정하지 말도록!","JPN":"うむ！　心配無用だ！","ENG":"Mm! Fear not!","TWN":"嗯！別擔心！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"그대들을 해하려 하는 이들은 내 칠색의 파사검이 일도양단을 낼 테니까!","JPN":"君たちに害をなす存在は、私の七色の破邪剣で一刀両断してやろう！","ENG":"Any who threaten you will be cleaved by my Iridescent Evil-fighting Greatsword!","TWN":"我的七色破邪劍會把想傷害你們的人一刀兩斷！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"하, 말이나 못 하면.","JPN":"はあ、言うことは立派なのですが。","ENG":"If only you'd stop talking...","TWN":"哈，光說不練。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"후훗… 여러분, 절대 다치시면 안 돼요?","JPN":"ふふっ……皆さん、絶対に怪我しないでくださいね？","ENG":"Haha... Everyone, don't get hurt, okay?","TWN":"呵呵……各位，絕對不能受傷喔？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"전투 준비는 끝났나, 아닐라?","JPN":"戦闘の準備は済ませたか、アニラ？","ENG":"Ready for battle, Anila?","TWN":"雅妮拉，準備好戰鬥了嗎？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"네. 준비는 완벽해요.","JPN":"はい、問題ありません。","ENG":"Yes. Perfectly prepared.","TWN":"是，很完美。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"아샤를 두고 오길 잘했네요.","JPN":"アーシャは置いてきて正解でしたね。","ENG":"Good thing we left Asha behind.","TWN":"留下阿莎真是正確的決定呢。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"이런 위험한 곳에 휘말렸다간 부전대장님을 볼 낯이 없으니까요.","JPN":"こんな危ない場所で巻き込まれでもしたら、副戦隊長に向ける顔がありません。","ENG":"I couldn't face Deputy Commander if she got dragged into this.","TWN":"如果讓她捲進這種危險的地方，我可沒臉見副戰隊長了。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"저승에서 눈을 부릅뜨고 있을 라비를 생각하니 등골이 서늘하군…….","JPN":"冥府で睨みつけているラビを想像すると、背筋が凍るような気分だ……","ENG":"Thinking of Ravi glaring from the afterlife chills me...","TWN":"一想到在黃泉張大雙眼瞪著我們的拉維，就覺得背脊發涼……"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"홀로 남을 아샤를 생각해서라도, 어떻게든 살아 돌아가야 한다.","JPN":"アーシャがこの世に一人取り残されないように、なんとしても生きて帰らねば。","ENG":"For Asha who'll be left alone, we must return alive somehow.","TWN":"就算是為了獨自留下的阿莎著想，我們無論如何都得活著回去。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"그 녀석 혼자로는 절대 대출금을 갚지 못할 테니까.","JPN":"あいつ一人では、ローンの返済は無理だろうからな。","ENG":"She could never pay off that loan by herself.","TWN":"那孩子靠自己絕對還不了貸款。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"아하하…….","JPN":"あはは……","ENG":"Ahaha...","TWN":"啊哈哈……"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"우리는 20년 전과는 달라요.","JPN":"私たちは、20年前とは違います。","ENG":"We're not who we were twenty years ago.","TWN":"我們已經不是20年前的我們了。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"이번엔 반드시…… 승리할 수 있을 거예요.","JPN":"今回は必ず……勝てます。","ENG":"This time... we will win.","TWN":"這次一定……會贏的。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"그렇다고 무리하다 다치지는 말도록.","JPN":"だが、無理して怪我はしないように。","ENG":"Just don't push and get hurt.","TWN":"話是這麼說，但也別逞強讓自己受傷了。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"너에게 무슨 일이라도 생기면 아샤한테 내가 혼난다.","JPN":"君に何かあったら、私がアーシャに怒られる。","ENG":"If anything happens to you, Asha will chew me out.","TWN":"你要是出了什麼事，我會被阿莎罵很慘。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"아, 아하하하…….","JPN":"あ、あははは……","ENG":"Ah, ahaha...","TWN":"啊啊哈哈哈……"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"넵! 힘내겠습니다!","JPN":"はい！　頑張ります！","ENG":"Yes, ma'am! I'll do my best!","TWN":"是！我會加油的！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"흐아아아!","JPN":"ふあああ！","ENG":"Hyaaah!","TWN":"呃啊啊啊！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_KNOCK_WOOD"},{"id":"L9_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"저질렀어! 저질러 버렸다고!","JPN":"言っちゃった！　言っちゃったよ！","ENG":"I did it! I actually did it!","TWN":"我說出口了！我真的說出口了！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"사람들에게 멋대로 희생을 강요하고, 버텨달라고 말했다고!","JPN":"勝手にみんなに犠牲を押し付けて、耐えてほしいなんて言ってしまった！","ENG":"I forced people to sacrifice and told them to hold out!","TWN":"我竟敢擅自要求大家犧牲，還叫大家撐住！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"으으으…….","JPN":"ううう……","ENG":"Ooh...","TWN":"嗚嗚嗚……"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"아니야, 이졸데. 너는 시니어잖아.","JPN":"ううん、イゾルデ。あなたはシニアなんだよ。","ENG":"No, Isolde. You're the Senior.","TWN":"不對，伊索德。妳是Senior。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"시니어로서 당연히 해야 했던 일이야.","JPN":"シニアとしてやるべきことをやっただけ。","ENG":"That was your duty as Senior.","TWN":"這是Senior該做的事。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"다들 저렇게 전의를 불태우는데 나만 궁상떨고 있을 수는 없어.","JPN":"みんなが闘志を燃やしてくれてるのに、私だけうじうじしてるわけにはいかないでしょ。","ENG":"Everyone's fired up. You can't be the only one moping.","TWN":"大家都燃起鬥志了，我怎麼能自己在這裡猶豫畏縮。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_KNOCK_WOOD"},{"id":"L17_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"후우우…….","JPN":"ふうう……","ENG":"Whew...","TWN":"呼……"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그래. 당당하게 굴어. 이졸데.","JPN":"そう。堂々と行こう、イゾルデ。","ENG":"Right. Stand tall, Isolde.","TWN":"對，抬頭挺胸，伊索德。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"넌 시니어야. 시니어의 자긍심을 가지고…….","JPN":"あなたはシニアなんだから。シニアとしての誇りを持って……","ENG":"You're the Senior. Hold that pride...","TWN":"妳是Senior，要有Senior的自信……"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_KNOCK_WOOD"},{"id":"L21_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"역시나 혼자 음습하게 중얼거리고 계셨군요. 시니어님.","JPN":"やはり、うじうじと独り言を呟いていたんですね、シニア様。","ENG":"As expected, muttering gloomily to yourself, Senior.","TWN":"您果然又在一個人哭喪著臉自言自語呢，Senior。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"히이익!","JPN":"ひいいっ！","ENG":"Eek!","TWN":"嗚哇！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"야! 노크는 하고 들어와야 할 것 아냐?!","JPN":"ちょっとぉ！　せめてノックぐらいはしてよね！","ENG":"Hey! Knock before you come in!","TWN":"喂！進來前要敲門吧？！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"1분 53초 정도 계속 두드렸습니다만, 별 대답이 없길래 들어왔습니다.","JPN":"1分53秒ほどノックしましたが、返事がなかったので入らせていただきました。","ENG":"I knocked for about one minute and fifty-three seconds. I heard no reply, so I entered.","TWN":"我大概敲了1分53秒但一直沒聽到回應，所以我才直接進來了。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"동시 사고 능력자인 시니어님이 이 소리를 듣지 못하고 있다면, 분명 큰일이 일어났을거라 생각했죠.","JPN":"同時思考能力者であるシニア様がノックの音に気づかないだなんて、何か大変なことが起きているのだろうと思ったのですが。","ENG":"If a multi-thinker like you didn't hear, I feared something had happened.","TWN":"如果擁有同步思考能力的Senior聽不見這麼大的聲音，那我只能判斷一定出事了。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"하지만 예상대로 시니어님은 그 유용한 능력을 땅을 파는 데나 사용하고 계셨군요.","JPN":"案の定、シニア様はその立派な能力で、勝手にネガティブ思考の渦に身を投げてしまったのですね。","ENG":"But as expected, you were using that useful gift to dig yourself into a hole.","TWN":"但果然如我所料，Senior把那珍貴的能力用在挖地洞上呢。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"하, 하지만 이렇게 남 앞에서 나서는 건 조금 무섭달까…….","JPN":"で、でもこうやって人前に出るのはちょっと怖いというか……","ENG":"W-well, taking the lead in front of others is scary...","TWN":"但、但是那樣站在大家面前還是有點可怕啦……"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"잘하셨습니다.","JPN":"よくできました。","ENG":"You did well.","TWN":"您做得很好。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시니어님의 연설로 아군의 전의가 다시 살아났습니다.","JPN":"シニア様の演説により、味方の士気が復活しました。","ENG":"Your speech rekindled our morale.","TWN":"因為Senior的演說，我軍又燃起士氣了。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"유능하시지만 리더의 그릇은 아니라 생각했던 제 판단을 재고하게 될 정도로요.","JPN":"有能だがリーダーの器ではない、と思っていた自分の判断について、もう一度考えさせられるほどに。","ENG":"Enough to make me reconsider my judgment that you were not leader material.","TWN":"甚至讓我開始重新思考自己對您雖然優秀但不適合當領袖這個判斷是否正確。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"……그거 칭찬이지?","JPN":"……それ、褒めてる？","ENG":"...That was praise, right?","TWN":"……妳這是在稱讚我嗎？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"물론입니다.","JPN":"もちろんです。","ENG":"Of course.","TWN":"當然。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"아, 그리고 사도가 활동을 시작했으니 이젠 저도 전선에 나서야 할 것 같습니다.","JPN":"あと、使徒が活動し始めたので、そろそろ私も戦場に出なければなりません。","ENG":"And since the Apostle is on the move, I should head to the front.","TWN":"啊，還有使徒開始行動，我也差不多得上前線了。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"마지막 싸움이 될지도 모르는 곳에서 후회를 남기고 싶진 않거든요.","JPN":"最後の戦いになるかもしれないのに、後悔を残したくないんです。","ENG":"I do not want regrets where this may be our last fight.","TWN":"我不想在可能是最後一戰的地方留下任何遺憾。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L43_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"뭐, 어차피 호위가 있으나 없으나 싸움에서 지면 죽는 건 똑같으니까.","JPN":"まあ……護衛がいてもいなくても、負けたら死ぬのは同じだしね。","ENG":"Well, with or without a bodyguard, if we lose we die anyway.","TWN":"反正不管有沒有護衛，只要戰敗就是死這點一樣吧。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"대, 대신 꼭 이기고 와야 해?!","JPN":"そ、その代わり、絶対勝って帰ってきてよね？","ENG":"J-just make sure you win, okay?!","TWN":"但、但是妳一定要贏著回來喔？！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"예전에도 얘기한 것 같지만 난 죽기 싫어!","JPN":"前も話したけど、私は死にたくない！","ENG":"I think I said this before, but I don't want to die!","TWN":"我以前好像也說過，我不想死！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"사도가 날 죽이러 오면 살려달라고 박박 빈 다음에 원하는 정보를 다 넘길 거니까……!","JPN":"もし使徒が私を殺しに来たら、すぐ土下座して知ってる情報全部吐き出してやるんだから……！","ENG":"If the Apostle comes to kill me, I'll beg for my life and hand over every secret...!","TWN":"要是使徒來殺我，我會跪下求饒、把知道的情報全部說出來……！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"훗, 타기리온의 사도는 사람을 산 채로 해부해 그림자로 만든다더군요.","JPN":"ふっ、タギリオンの使徒は人を生きたまま解剖してシャドウにするらしいですよ。","ENG":"Haha. Thagirion's Apostle dissects people alive and makes them into Shadows.","TWN":"哼，聽說塔基里翁的使徒會把活生生的人拿去解剖，做成影子。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그 사도가 시니어님을 세 조각, 만 조각으로 나누지만 않는다면 그렇게 하셔도 상관없습니다.","JPN":"その使徒がシニア様の体を3個に……1万個に分けないでくれるなら、そうしても構いません。","ENG":"As long as she does not chop you into a few or ten thousand pieces, I will not stop you.","TWN":"只要那位使徒不把Senior切成三塊或一萬塊，那麼您想怎麼做都可以喔。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"히이이익!","JPN":"ひいいっ！","ENG":"Eeeeek!","TWN":"咿咿咿咿！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그럼, 조금이라도 빨리 선로전환기를 가동해 주길 바랍니다.","JPN":"では、少しでも早く線路転換器を稼働させてください。","ENG":"Then please activate the Track Switcher as soon as possible.","TWN":"那麼，請儘快啟動轉換器吧。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시니어님도, 우리도 모두 살고 싶으니까요.","JPN":"シニア様も、私たちも皆生き延びたいですから。","ENG":"Because you and we all want to live.","TWN":"不論是Senior還是我們，大家都想活下去。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"마, 맡겨만 둬.","JPN":"ま、任せて。","ENG":"L-leave it to me.","TWN":"交、交給我。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이제 이터니움만 채워 넣으면 완성이니까.","JPN":"あとはエタニウムを詰めるだけだから。","ENG":"All that's left is filling it with Eternium.","TWN":"只要填滿永恆之金就完成了。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"훗, 알겠습니다.","JPN":"ふっ、分かりました。","ENG":"Haha. Understood.","TWN":"呵，我知道了。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시니어님은 고집불통에 어린애 같고, 때로는 시니어의 자격이 있는지 의심할 때가 많지만.","JPN":"シニア様は頑固で、子供っぽくて、シニアとしての資格があるのか疑わしくなる時も多々ありますが……","ENG":"You're stubborn, childish, and sometimes unfit for Senior. But I trust you.","TWN":"Senior固執到像個小孩子，很多時候都會讓人懷疑您到底適不適合當Senior。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"저는 시니어님을 믿고 있으니까요.","JPN":"私はシニア様を信じています。","ENG":"I believe in you.","TWN":"但我相信您。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시니어님. 운송 수단이 준비되었습니다.","JPN":"シニア、輸送手段の準備が終わりました。","ENG":"Senior. Transport is ready.","TWN":" Senior，運輸工具準備好了。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"좋아. 사람들을 모아줘.","JPN":"よし、じゃあ皆を呼んで。","ENG":"Good. Gather everyone.","TWN":"好，召集大家。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"다들 정비는 충분히 마쳤지?","JPN":"整備は十分できたよね？","ENG":"All maintenance done?","TWN":"大家都整備好了嗎了？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"내가 할 말은 아까 다 했으니 덧붙일 말은 없고…….","JPN":"言いたいことはさっきので全部伝えたし、もう言うことはない。だから……","ENG":"I said what I had to earlier, so nothing to add...","TWN":"我該說的剛才都說了，沒有要補充的……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"살아서 돌아와.","JPN":"生きて帰ってきて。","ENG":"Come back alive.","TWN":"活著回來。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"나도 최선을 다할게.","JPN":"私も全力を尽くすから。","ENG":"I'll do my best too.","TWN":"我也會盡全力。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"subtitle","speaker":null,"text":{"KOREA":"로터스, 대균열 지대","JPN":"ロータス、大亀裂地帯","ENG":"Lotus, Grand Dimension Crevice","TWN":"洛德斯，大峽谷地帶"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"현재 대균열로부터 뻗어 나온 뿌리가 로터스를 잠식한 상태입니다.","JPN":"現在、大亀裂から伸びてきた木の根がロータスを蝕んでいる状況です。","ENG":"The roots from the Grand Dimension Crevice are now engulfing Lotus.","TWN":"目前從自大峽谷延伸的根系已侵蝕洛德斯。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그로 인해 착륙할 자리를 찾기가 어려워 전원 긴급 강하로 작전을 시작합니다.","JPN":"そのせいで着陸地点の選定が困難になり、全員緊急降下で作戦を開始します。","ENG":"Landing zones are scarce, so we begin with an emergency airdrop.","TWN":"因此難以找到安全的降落點，將以全員緊急迫降方式展開作戰。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"바루나 전대장님. 저거 보여?","JPN":"ヴァルナ戦隊長、見えてる？","ENG":"Varuna Division Commander, do you see that?","TWN":"伐樓拿戰隊長，你看到那個了嗎？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"사도로군. 본격적으로 움직이는 것을 보니 저 뿌리가 뻗어 나오는 게 녀석의 계획인가?","JPN":"使徒か。本格的に動き出したということは、あの根を伸ばすことがやつの狙いか？","ENG":"The Apostle. If she's moving in earnest, were those roots part of her plan?","TWN":"是使徒。看那傢伙正式開始行動，那些蔓延的根大概就是它的計畫吧？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"그럴 가능성이 높아 보이네.","JPN":"その可能性が高そうね。","ENG":"Most likely.","TWN":"看來可能性很高。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"무슨 원리로 저게 현실 세계를 이 정도로 침식시키는지는 모르겠지만 말이야.","JPN":"あれがどういう仕組みで現実世界を侵食しているかは、まだ不明だけど。","ENG":"No idea how it corrodes the Normalside this badly, though.","TWN":"雖然不知道它是用什麼原理侵蝕到現實世界成這樣……。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"좋아. 그 정도면 충분해.","JPN":"よし。それで十分だ。","ENG":"That's enough.","TWN":"很好，知道這些就夠了。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"내가 선두에 서서 적의 공격을 받아내겠다.","JPN":"私が先頭に立って敵の攻撃を受け止める。","ENG":"I'll take point and soak the enemies' attacks.","TWN":"我會站在最前面承受敵人的攻擊。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"모두 전투를 준비하도록.","JPN":"皆、戦闘の準備を。","ENG":"Prepare for battle.","TWN":"全員做好戰鬥準備。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"좋습니다.","JPN":"いいでしょう。","ENG":"Understood.","TWN":"很好。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"작전 시작 전에, 하나만 기억하세요.","JPN":"作戦開始に当たって、1つだけ覚えていてください。","ENG":"Before we start, remember one thing.","TWN":"作戰開始前，只要記住一件事。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"우리는 선로전환기가 가동될 시간을 버는 겁니다.","JPN":"私たちは、線路転換器が稼働するまでの時間を稼ぐのです。","ENG":"We are buying time for the Track Switcher to activate.","TWN":"我們要爭取啟動轉換器的時間。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그럼, 로터스 관리국이 명령합니다.","JPN":"では、ロータス管理局から命令します。","ENG":"Then, the Lotus Administration issues the following order.","TWN":"那麼，洛德斯管理局下令。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"전원! 즉시 강하합니다!","JPN":"全員！　直ちに降下！","ENG":"All units! Descend!","TWN":"全員！立即迫降！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"전원, 워치의 초침과 이터니움 쉴드량을 확인하며 전투하도록.","JPN":"全員、ウォッチの秒針とエタニウムシールドの残量を確認しながら戦うように。","ENG":"Check your Watch's second hand and Eternium shields mid-fight.","TWN":"各位，確認手錶指針與永恆之金護盾量，進行戰鬥。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"뿌리가 잠식한 구역의 침식파 밀도는 상상을 뛰어넘고 있으니.","JPN":"根に蝕まれている区域の侵食波密度は、想像を超えるほどだ。","ENG":"Corruption ray density in the rooted zones is beyond imagination.","TWN":"被根系侵蝕的區域，侵蝕波密度遠超於想像。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"칫, 모두 내 뒤로!","JPN":"ちっ、皆私の後ろに下がれ！","ENG":"Tch! Everyone behind me!","TWN":"嘖，全員到我後方！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"보기와는 다르게 졸렬하게 싸우는 걸 즐기는 성격이었나?","JPN":"見た目にそぐわず、卑劣な戦いを好むタイプか？","ENG":"So you enjoy fighting dirty despite the grand look?","TWN":"沒想到跟你外表不同，居然喜歡用卑鄙的方式戰鬥啊？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"사도.","JPN":"使徒。","ENG":"Apostle.","TWN":"使徒。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"스스로 불 속에 뛰어들었구나, 미물들아.","JPN":"飛んで火に入るか、下等な微物どもよ。","ENG":"You threw yourselves into the fire, vermin.","TWN":"自投羅網了啊，渺小的人類。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"이곳은 왕의 축복을 받은 땅.","JPN":"ここは王に祝福されし地。","ENG":"This ground is blessed by the queen.","TWN":"此地乃被王祝福的大地。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그런 곳에서 감히 본래의 힘을 행사할 수 있는 나를 이길 거라 생각하는 것인가?","JPN":"このような場所で、本来の力を発揮できる余に勝てると思っているのか？","ENG":"Do you think you can defeat me, who can exercise my true power here?","TWN":"在這種地方我能行使原本的力量，你們真的以為能贏過我？"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그렇다. 사도.","JPN":"当然だ、使徒。","ENG":"I do, Apostle.","TWN":"沒錯，使徒。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"이곳은 내가 나고 자라 평생을 지켜온 땅이기도 하다.","JPN":"ここは私が生まれ育ち、一生をかけ守ってきた地。","ENG":"This is the land where I was born, raised, and swore to protect.","TWN":"這裡同時也是我出生、成長，用一生守護的土地。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그런 내가 너에게 질 것이라 생각하는 건가?","JPN":"そんな私が、お前に負けると思うか？","ENG":"Do you think I will lose to you here?","TWN":"你以為我會輸給你嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그동안 스러진 수많은 세계의 미물들이 내 앞에서 그런 말을 지껄이곤 사라졌지.","JPN":"これまで滅びた数多の世界の微物は皆、余の前で同じことをほざいては散っていった。","ENG":"Countless vermin from fallen worlds said the same and vanished before me.","TWN":"在過去消逝的無數世界裡，渺小的人類總會在我面前說出同樣的話後消失。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"너희라고 다를 줄 아느냐?","JPN":"貴様らは違うとでも？","ENG":"Why would you be different?","TWN":"妳以為你們不一樣嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"미물들의 수가 많아졌다고 하여 그것이 미물이 아니게 되는 것이 아니다.","JPN":"数を増やしたところで、微物は微物に過ぎない。","ENG":"Numbers do not elevate vermin beyond vermin.","TWN":"就算渺小的人類變多了，還是一樣渺小。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"그건 너희도 마찬가지지 않을까?","JPN":"それはあなたたちも同じじゃないかしら？","ENG":"Doesn't that apply to you too?","TWN":"你們不也一樣嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"제아무리 모르스를 복제해도 모르스와 똑같은 사람이 태어나지 않았듯이.","JPN":"いくらモールスを複製してもモールスと同じ人間にはならなかったように……","ENG":"Just like how no matter how many Mors clones you make, it's not the same person.","TWN":"不管再怎麼複製莫爾斯，也不可能誕生與他完全相同的人。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"똑같이 생긴 꼭두각시를 더 만든다고 해서 너희가 가족인 건 아니잖아?","JPN":"同じ見た目の操り人形を増やしても、あなたたちが家族になれるわけじゃないでしょう？","ENG":"Making more identical puppets doesn't make them family.","TWN":"就算做出一堆長得一模一樣的傀儡，你們也不會變成家人吧？"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"건방진 것!","JPN":"生意気な！","ENG":"Insolent!","TWN":"放肆的東西！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"후훗, 화가 잔뜩 나셨네?","JPN":"ふふっ、怒った？","ENG":"Heh heh. Did I strike a nerve?","TWN":"呵呵，這麼生氣啊？"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"나는 물론이고, 우리 애들이 당신들 때문에 쌓인 게 좀 많거든.","JPN":"私もだけど、うちの子どもたちもあなたたちに返したい借りが結構あるのよ。","ENG":"It's not just me, my entire division's got a lot to settle with your lot.","TWN":"不只是我，我的夥伴們也因為你們累積很多怒氣。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"겨우 이 정도로 어린애처럼 화를 내기엔…….","JPN":"この程度で怒られると困るわ。","ENG":"Throwing a tantrum over this much...","TWN":"現在就像小孩一樣發火太早了……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"우리가 들려줘야 할 이야기들이 너무 많아서 말이야!","JPN":"聞いてもらいたい話が、山積みなんだからね！","ENG":"We've got too many stories to tell you!","TWN":"我們還有很多話要說呢！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면 너희 미물들의 허황된 망상을 짓밟아줘야 정신을 차리겠군.","JPN":"ならば、貴様らのその虚しい妄想を踏みつけて、立場というものを分からせてやろう。","ENG":"Then I'll crush your delusions so you wake up.","TWN":"既然如此，看來得徹底踐踏你們這些渺小人類的荒唐妄想，才會清醒吧。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"침식체들이 몰려오고 있습니다!","JPN":"侵食体が押し寄せてきています！","ENG":"C.O.s incoming!","TWN":"侵蝕體正蜂擁而來！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"전원, 주의하십시오!","JPN":"全員、注意を！","ENG":"All units, stay sharp!","TWN":"全員注意！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕의 병사들아. 저들을 자비 없이 몰아붙여라.","JPN":"王の兵士たちよ、奴らを追い込め。慈悲を与えるな。","ENG":"Soldiers of the queen. Drive them without mercy.","TWN":"王之兵士們啊，毫不留情地上啊。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"불 속에 들어온 불나방들이 어떻게 타오르는지 보여줘야겠구나.","JPN":"火に飛び込んだ虫けらがどう燃やされるのか見せてやれ。","ENG":"Show these moths how they will burn when they fly into the flame.","TWN":"得讓這些撲火的飛蛾看看自己是怎麼被燃燒殆盡。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};